INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('65fa2a41fa1068db', 'VT', '["federal","state","county"]', 'ballot_access', 'Does Vermont have an open or closed primary system?', '["Vermont primary voting rules","Do I have to register with a party to vote in the VT primary?","Can unaffiliated voters participate in the Vermont primary?"]', 'Vermont operates a fully open primary system. Voters do not register with a political party in Vermont. Any registered voter may request the primary ballot of any major party at the polling place on Election Day. However, they may only vote in one party''s primary per election.', 'https://sos.vermont.gov/elections/voters/voter-faqs/', 'Vermont Secretary of State - Voter FAQs', '2026-05-17', 'static', 'official_source_direct', 'All voters and candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('d13c71773ff40974', 'VT', '["federal","state","county"]', 'runoff_rules', 'Does Vermont hold primary runoff elections?', '["What is the threshold to win a primary in VT?","Does Vermont require a majority to win a primary?","Vermont primary runoff rules"]', 'No. Vermont does not hold primary runoff elections. A candidate does not need to secure a majority to win the party''s nomination; the candidate who receives a simple plurality (the most votes) in the primary advances directly to the general election.', 'https://sos.vermont.gov/elections/', 'Vermont Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'All primary candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('c5fc6b4f4a3104e1', 'VT', '["federal","state","county"]', 'ballot_access', 'Are write-in candidates required to file paperwork in Vermont?', '["Do write-in votes count automatically in VT?","How to register as a write-in candidate in Vermont","Write-in filing deadline Vermont"]', 'Yes. Counter to older baseline assumptions, Vermont DOES require paperwork for write-in votes to be tabulated for a specific candidate. Under 17 V.S.A. § 2370, a write-in candidate for federal, state, or legislative office must file a designated form with the Secretary of State no later than 5:00 p.m. on the Thursday preceding the election.', 'https://legislature.vermont.gov/statutes/section/17/049/02370', 'Vermont Statutes 17 V.S.A. § 2370', '2026-05-17', 'static', 'statute_citation', 'Write-in candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('05573d68f161b241', 'VT', '["federal","state","county"]', 'filing_requirements', 'What is the candidate filing deadline for major party candidates in Vermont for 2026?', '["When do candidates file for office in Vermont?","Vermont filing deadline 2026","May filing deadline VT"]', 'For major party candidates participating in the 2026 primary election, the filing deadline to submit petitions and consent forms is 5:00 p.m. on the fourth Thursday after the first Monday in May. For the 2026 cycle, this deadline is May 28, 2026.', 'https://sos.vermont.gov/elections/election-info-resources/faqs', 'Vermont Secretary of State - Candidate FAQ', '2026-05-17', 'per_cycle', 'official_source_direct', 'Major party candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('8d86606b3b60b54c', 'VT', '["federal","state"]', 'ballot_access', 'What is the filing deadline and signature threshold for independent candidates in Vermont?', '["Independent candidate ballot access Vermont","Running without a party in VT 2026","Independent filing deadline Vermont"]', 'Independent candidates must file a statement of nomination (petition) and a consent form. The deadline for independent candidates is 5:00 p.m. on the Thursday before the statewide primary (August 6, 2026). The signature requirement varies by office, with 500 required for statewide and federal offices, and fewer for legislative seats.', 'https://sos.vermont.gov/elections/election-info-resources/faqs', 'Vermont Secretary of State - Candidate FAQ', '2026-05-17', 'per_cycle', 'official_source_direct', 'Independent candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('457f3661ecd71955', 'VT', '["federal","state","county"]', 'ballot_access', 'Does Vermont have a sore loser law?', '["Can I run as an independent if I lose the VT primary?","Vermont sore loser statute","General election ballot access after primary defeat VT"]', 'Yes. Vermont expanded its sore loser laws through Act 70 (H.429) in 2023. A candidate who runs and loses in a major party''s primary election is explicitly prohibited from subsequently appearing on the general election ballot as an independent candidate or running as a write-in candidate for the same office.', 'https://legislature.vermont.gov/Documents/2024/Docs/BILLS/H-0429/H-0429%20As%20passed%20by%20the%20House%20Official.pdf', 'Vermont General Assembly (Act 70 / H.429)', '2026-05-17', 'static', 'statute_citation', 'Major party candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('4ef1387c98696807', 'VT', '["state"]', 'ballot_access', 'Do the Governor and Lieutenant Governor run on a joint ticket in Vermont?', '["Vermont joint ticket rules","How are Lt Gov candidates selected in VT?","Does the Governor pick a running mate in Vermont?"]', 'No. In Vermont, the Governor and Lieutenant Governor are elected completely separately. They run in separate primary and general elections and appear as distinct items on the ballot, meaning voters can elect a Governor and Lieutenant Governor from two different political parties.', 'https://sos.vermont.gov/elections/', 'Vermont Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Statewide executive candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('7853483784ae1a0a', 'VT', '["federal","state","county"]', 'election_dates', 'When are the primary and general elections in Vermont for 2026?', '["Vermont primary date 2026","When is Election Day 2026 in Vermont?","August primary Vermont"]', 'The Vermont primary election will be held on Tuesday, August 11, 2026. The general election will be held on Tuesday, November 3, 2026. Polls open between 5:00 a.m. and 10:00 a.m. (depending on the town) and all polls close uniformly at 7:00 p.m.', 'https://sos.vermont.gov/elections/voters/', 'Vermont Secretary of State', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('41260392c08394ea', 'VT', '["state"]', 'election_dates', 'Is Governor Phil Scott running for election in 2026?', '["Vermont Governor election 2026","Who is defending the VT Governor seat?","Is Phil Scott on the 2026 ballot?"]', 'Yes. Vermont is one of only two states (along with New Hampshire) that still elects its Governor to two-year terms. Therefore, the gubernatorial seat is on the ballot in every even-numbered year, including 2026.', 'https://ballotpedia.org/Governor_of_Vermont', 'Ballotpedia - Governor of Vermont', '2026-05-17', 'static', 'secondary_source', 'Gubernatorial candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('23f7345413b34434', 'VT', '["federal"]', 'election_dates', 'Which U.S. Senate seat is up for election in Vermont in 2026?', '["Is Bernie Sanders up for re-election in 2026?","When is Peter Welch''s next election?","Vermont US Senate cycle 2026"]', 'Neither U.S. Senate seat in Vermont is on the ballot in 2026. Senator Bernie Sanders (Class 1) was re-elected in 2024 and is next up in 2030. Senator Peter Welch (Class 3) was elected in 2022 and is next up in 2028.', 'https://www.senate.gov/senators/Class_I.htm', 'U.S. Senate - Class I Senators', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('dc6853b3b76d1f94', 'VT', '["federal"]', 'election_dates', 'How many U.S. House districts are in Vermont for the 2026 election?', '["Vermont congressional apportionment","Are all VT congressional seats up in 2026?","Number of US Representatives from Vermont"]', 'Vermont is apportioned exactly 1 U.S. House district. The entire state is represented by a single At-Large district, which is on the 2026 ballot for a two-year term.', 'https://sos.vermont.gov/elections/', 'Vermont Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('98435438f2fb2254', 'VT', '["state"]', 'election_dates', 'Which Vermont State Legislature seats are up for election in 2026?', '["Are all Vermont House seats up in 2026?","Vermont Senate election cycle 2026","Which legislative districts are on the ballot in VT?"]', 'In Vermont, all members of the General Assembly serve two-year terms. Therefore, all 150 seats in the Vermont House of Representatives and all 30 seats in the Vermont State Senate are on the 2026 ballot.', 'https://legislature.vermont.gov/', 'Vermont General Assembly', '2026-05-17', 'per_cycle', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('91d5aec6bddd57a8', 'VT', '["state"]', 'election_dates', 'Which statewide executive offices are up for election in Vermont in 2026?', '["Is the Attorney General up in 2026?","VT statewide election list 2026","When is the Secretary of State election in VT?"]', 'Because Vermont utilizes two-year terms for all its statewide executives, ALL of them are on the 2026 ballot. This includes the Governor, Lieutenant Governor, Secretary of State, Treasurer, Auditor of Accounts, and Attorney General.', 'https://sos.vermont.gov/elections/', 'Vermont Secretary of State', '2026-05-17', 'per_cycle', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('e890ff8612ccdd23', 'VT', '["judicial"]', 'election_dates', 'How are Vermont Supreme Court justices selected and are they on the ballot?', '["Vermont judicial elections 2026","Are VT judges elected or appointed?","Supreme Court elections Vermont"]', 'Vermont does NOT hold judicial elections. Supreme Court justices are appointed by the Governor from a list provided by the Judicial Nominating Board, with the consent of the State Senate. They serve six-year terms and are retained by a majority vote of the General Assembly, not by the voters.', 'https://www.vermontjudiciary.org/', 'Vermont Judiciary', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('1b58cd1d3b7d0a5e', 'VT', '["state"]', 'election_dates', 'What is the schedule for the Vermont General Assembly sessions?', '["When does the VT legislature meet?","Vermont legislative session length","Is the Vermont legislature full time?"]', 'The Vermont General Assembly is a part-time legislature that meets annually. The regular session convenes on the Wednesday following the first Monday in January and generally adjourns in early to mid-May.', 'https://legislature.vermont.gov/', 'Vermont General Assembly', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('85043206acf4583d', 'VT', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Governor of Vermont?', '["Age and residency for Vermont Governor","Vermont Constitution Governor qualifications","Who is eligible to be Governor of VT?"]', 'Under Chapter II, Section 23 of the Vermont Constitution, a candidate for Governor or Lieutenant Governor must be a resident of Vermont for at least four years preceding the day of the election.', 'https://sos.vermont.gov/elections/', 'Vermont Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Gubernatorial candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('cd80b9b9abfbba70', 'VT', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for the Vermont State Legislature?', '["Qualifications for VT State Representative","Age requirement Vermont State Senate","Do I have to live in my district to run in VT?"]', 'A candidate for the State Senate or House of Representatives must be a resident of Vermont for at least two years and a resident of the legislative district they seek to represent for at least one year immediately preceding the election.', 'https://sos.vermont.gov/elections/', 'Vermont Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('41f8acc7c63e076e', 'VT', '["federal"]', 'candidate_eligibility', 'What are the eligibility requirements for U.S. House candidates in Vermont?', '["US House residency requirements Vermont","Age to run for Congress in Vermont","Federal constitutional requirements for VT candidates"]', 'Federal candidates must meet standard U.S. Constitutional requirements: U.S. House members must be at least 25 years old, a U.S. citizen for 7 years, and an inhabitant of the state when elected.', 'https://sos.vermont.gov/elections/', 'Vermont Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('02d3d468eef38d54', 'VT', '["state"]', 'candidate_eligibility', 'What are the term limits for the Vermont Governor?', '["How many terms can a Vermont Governor serve?","Phil Scott term limits VT","Vermont executive term limit law"]', 'Vermont is one of the few states that does not impose term limits of any kind on its Governor or other statewide executive officers. Governor Phil Scott is fully eligible to continue seeking consecutive two-year terms.', 'https://ballotpedia.org/Governor_of_Vermont', 'Ballotpedia - Governor of Vermont', '2026-05-17', 'static', 'secondary_source', 'Gubernatorial candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('976e6d036e84ed87', 'VT', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Attorney General in Vermont?', '["Qualifications to run for Attorney General in VT","Do I need to be a member of the bar to be VT AG?","Legal requirements for Vermont Attorney General"]', 'The Attorney General is an elected statewide constitutional officer. Under the Vermont Constitution, the only explicitly enumerated requirement is that the candidate be a ''freeman'' (a registered voter) of the state.', 'https://sos.vermont.gov/elections/', 'Vermont Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('ab6588a2a1845fad', 'VT', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Lieutenant Governor in Vermont?', '["Vermont Lt Gov requirements","Does the Lt Gov have the same requirements as the Governor in VT?","Qualifications for Lieutenant Governor of Vermont"]', 'Under Chapter II, Section 23 of the Vermont Constitution, the qualifications for Lieutenant Governor are identical to those for Governor. A candidate must have been a resident of Vermont for at least four years preceding the election.', 'https://sos.vermont.gov/elections/', 'Vermont Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Statewide executive candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('5a567d3122dbb262', 'VT', '["state"]', 'candidate_eligibility', 'Are there special financial disclosure requirements to run for state office in Vermont?', '["Vermont candidate tax return requirement","State Ethics Commission disclosure VT","Financial filing requirements for Vermont candidates"]', 'Yes. Each candidate for non-federal statewide office, state senate, state representative, and county office must file a Financial Disclosure form with the State Ethics Commission alongside their petition. Furthermore, candidates for statewide office (Gov, Lt Gov, Sec of State, Treasurer, Auditor, AG) must submit a copy of their most recent IRS Form 1040.', 'https://sos.vermont.gov/elections/election-info-resources/faqs', 'Vermont Secretary of State - Candidate FAQ', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('6656daac374ac5ca', 'VT', '["federal","state","county","municipal"]', 'voter_interaction', 'Is a photo ID required to vote in person in Vermont?', '["Vermont voter ID requirements","Do I need my driver''s license to vote in VT?","Acceptable ID for Vermont voting"]', 'No. Vermont does NOT require voters to present a photo ID to vote in person at the polls. (The only exception is for certain first-time voters who registered by mail without providing a driver''s license number or SSN, who must show an ID or a current utility bill/bank statement).', 'https://sos.vermont.gov/elections/voters/voter-faqs/', 'Vermont Secretary of State - Voter FAQs', '2026-05-17', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('41e54caec61374d8', 'VT', '["federal","state","county","municipal"]', 'voter_interaction', 'Is Vermont a universal mail ballot state, and is no-excuse absentee voting allowed?', '["Do all voters get a mail ballot in Vermont?","Vermont vote-by-mail system","Do I need an excuse to vote absentee in VT?"]', 'Yes. Under Act 60, Vermont is a Universal Mail Voting state for general elections. The state automatically mails a ballot to every active registered voter by October 1 of an even-numbered year. For primary and local elections, ballots are not mailed automatically, but any voter may request a no-excuse absentee ballot.', 'https://sos.vermont.gov/elections/voters/early-absentee-voting/', 'Vermont Secretary of State - Voting by Mail', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('c5f8fbe2d184b83c', 'VT', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Vermont offer early in-person voting?', '["Can I vote early in person in VT?","Vermont early voting dates 2026","When does early voting start in Vermont?"]', 'Yes. Vermont offers one of the longest early voting periods in the nation. Any registered voter may vote early in person at their town or city clerk''s office starting 45 days before the election (which falls on June 27 for the August 2026 primary).', 'https://sos.vermont.gov/elections/voters/early-absentee-voting/', 'Vermont Secretary of State - Early Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('c8076f066029b855', 'VT', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the voter registration deadline and does Vermont offer same-day registration?', '["Last day to register to vote in VT","Vermont same day voter registration","Voter registration deadline 2026 Vermont"]', 'Vermont has NO advance voter registration deadline. The state offers unrestricted Same-Day Registration (SDR). Eligible individuals can register to vote on any day up to and including Election Day at their town clerk''s office or directly at their polling place.', 'https://sos.vermont.gov/elections/voters/registration/', 'Vermont Secretary of State - Voter Registration', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('b83b729b2ecfded7', 'VT', '["federal","state","county","municipal"]', 'voter_interaction', 'How are voting rights restored for individuals with felony convictions in Vermont?', '["Can felons vote in Vermont state?","Felony voting rights restoration VT","Voting on parole in Vermont"]', 'In a major distinctive, Vermont is one of only two states (along with Maine) where felony voting rights are NEVER lost. Individuals convicted of a felony retain their right to vote, even while actively incarcerated. They vote via absentee ballot at their last voluntary residence.', 'https://legislature.vermont.gov/statutes/section/28/011/00807', 'Vermont Statutes 28 V.S.A. § 807', '2026-05-17', 'static', 'statute_citation', 'Voters', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('723398dc09a9692c', 'VT', '["county"]', 'voter_interaction', 'How is election administration structured across Vermont jurisdictions?', '["Vermont county election administration","How many town clerks in VT?","Local election control Vermont municipalities"]', 'While Vermont has 14 geographic counties, election administration is conducted almost entirely at the municipal level by Town and City Clerks across 246 distinct municipalities. Statewide campaigns must coordinate heavily with these local clerks regarding ballot logistics and early voting.', 'https://sos.vermont.gov/elections/town-clerks/', 'Vermont Secretary of State - Town Clerks', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('5e3fa5a2259094fa', 'VT', '["federal","state","county","municipal"]', 'voter_interaction', 'How can campaigns access the Vermont voter file?', '["Vermont voter database access cost","How to get the voter list in VT","What data is included in the Vermont voter file?"]', 'Campaigns and political committees can request the statewide voter registration list from the Secretary of State. The file includes voter names, addresses, and voting history (but not party affiliation, as Vermont does not record it). The data is strictly restricted to political and electoral purposes.', 'https://sos.vermont.gov/elections/', 'Vermont Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('5207f37741835111', 'VT', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the deadline to return an absentee mail-in ballot in Vermont?', '["When is the last day to mail my ballot in VT?","Vermont mail ballot postmark deadline","What time are ballots due in Vermont?"]', 'Voted absentee and universal mail ballots must be physically received by the local town clerk''s office or polling place by the close of polls (7:00 p.m.) on Election Day. Vermont does NOT accept ballots arriving late based on postmark dates.', 'https://sos.vermont.gov/elections/voters/early-absentee-voting/', 'Vermont Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('260bc8d0d6f7aa86', 'VT', '["state","county","municipal"]', 'finance_ethics', 'Which agency administers campaign finance tracking in Vermont?', '["Where do I file campaign finance reports in VT?","What is the Vermont Campaign Finance system?","Does the VT Secretary of State handle campaign finance?"]', 'Campaign finance and disclosure laws in Vermont are administered and enforced by the Office of the Secretary of State. Candidates use the online Vermont Campaign Finance System to file their required contribution and expenditure reports.', 'https://sos.vermont.gov/elections/campaign-finance/', 'Vermont Secretary of State - Campaign Finance', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('51d09e965838ffe6', 'VT', '["state","county"]', 'finance_ethics', 'What are the individual campaign contribution limits in Vermont for the 2026 cycle?', '["Are there contribution limits in Vermont?","VT individual donation caps 2026 election","Maximum donation to state legislature Vermont"]', 'Vermont imposes contribution limits per TWO-YEAR election cycle, not per election. For the 2025-2026 cycle, individuals may contribute up to $5,180 to a gubernatorial candidate, $1,940 to a State Senate candidate, and $1,290 to a State Representative candidate for the entire cycle.', 'https://ballotpedia.org/Campaign_finance_requirements_in_Vermont', 'Ballotpedia / Vermont Secretary of State', '2026-05-17', 'per_cycle', 'secondary_source', 'Candidates and Donors', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('04011a945204fb69', 'VT', '["state","county","municipal"]', 'finance_ethics', 'Are corporate contributions permitted in Vermont campaigns?', '["Corporate contribution ban Vermont state","Can a business donate to my campaign in VT?","Corporate campaign finance rules Vermont"]', 'Yes. Unlike most other New England states, direct contributions from the general treasury of a corporation or labor union to a candidate''s campaign committee are PERMITTED in Vermont. They are subject to the exact same per-cycle limits as individual donors ($5,180 Gov, $1,940 Senate, $1,290 House).', 'https://ballotpedia.org/Campaign_finance_requirements_in_Vermont', 'Ballotpedia / Vermont Secretary of State', '2026-05-17', 'static', 'secondary_source', 'Candidates and Businesses', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('289d96ffc7a6944e', 'VT', '["state","county"]', 'finance_ethics', 'What are the PAC contribution limits to candidates in Vermont?', '["VT PAC donation limits to candidates 2026","Political committee vs individual contribution limit Vermont","Maximum PAC gift to state legislator VT"]', 'In Vermont, standard Political Action Committees (PACs) are subject to the EXACT SAME contribution limits as individuals and corporations. For the 2025-2026 cycle, a PAC may contribute up to $5,180 to a gubernatorial candidate, $1,940 to a State Senate candidate, and $1,290 to a State House candidate per two-year cycle.', 'https://ballotpedia.org/Campaign_finance_requirements_in_Vermont', 'Ballotpedia / Vermont Secretary of State', '2026-05-17', 'per_cycle', 'secondary_source', 'State and County candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('8a8d7c16f0f36051', 'VT', '["state","county","municipal"]', 'finance_ethics', 'What is the general campaign finance reporting schedule for Vermont candidates?', '["VT SOS filing dates 2026","When are campaign finance reports due in VT?","Vermont pre-primary and pre-general report deadlines"]', 'During an election year, Vermont candidates must file campaign finance reports on the 15th of March and July. Leading up to an election, they must file reports 30 days before, 15 days before, and 4 days before both the primary and general elections, as well as a post-election report two weeks after.', 'https://outside.vermont.gov/dept/sos/Elections_Division/campaign_finance/campaign_finance_guide.pdf', 'Vermont Secretary of State - Campaign Finance Guide', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('ec63029c85c76099', 'VT', '["state","county","municipal"]', 'finance_ethics', 'What are Vermont''s rapid disclosure requirements for late mass media expenditures?', '["Vermont 24-hour large contribution report","Late mass media reporting Vermont SOS","When do I file a rapid report in VT?"]', 'Under Vermont law, any candidate or political committee that makes expenditures for ''mass media activities'' totaling $500 or more within the 45 days before an election must file a Mass Media Report with the Secretary of State within 24 hours of the expenditure.', 'https://outside.vermont.gov/dept/sos/Elections_Division/campaign_finance/campaign_finance_guide.pdf', 'Vermont Secretary of State - Campaign Finance Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('002a4c942d1ebe40', 'VT', '["state"]', 'finance_ethics', 'Does Vermont provide public financing for state campaigns?', '["Public matching funds for Vermont Governor","State funded campaigns Vermont status","Government campaign grants VT"]', 'Yes. Vermont offers optional public financing solely for candidates seeking the office of Governor or Lieutenant Governor. Qualifying candidates who accept strict spending limits and raise a threshold of small-dollar qualifying contributions receive public campaign grants from the state.', 'https://sos.vermont.gov/elections/campaign-finance/', 'Vermont Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'State candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('3a4f8746b10e87c0', 'VT', '["state"]', 'finance_ethics', 'Is there a session freeze on campaign contributions for Vermont legislators?', '["Can Vermont legislators raise money during session?","Lobbyist contribution ban VT legislature","Legislative session contribution rules Vermont"]', 'Yes. Vermont enforces a session freeze specifically targeted at lobbying entities. While the General Assembly is in regular session, any registered lobbyist, lobbyist employer, or lobbying firm is strictly prohibited from making or soliciting campaign contributions to legislators or statewide officeholders.', 'https://www.jdsupra.com/legalnews/contributor-beware-state-level-2397699/', 'JDSupra - Contributor Beware', '2026-05-17', 'static', 'secondary_source', 'State legislative candidates and Lobbyists', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('cfcaee225d191a5b', 'VT', '["federal","state"]', 'redistricting', 'Who draws Vermont''s state legislative maps?', '["Does the VT legislature draw district maps?","Who has the authority to draw district lines in Vermont?","Vermont redistricting commission"]', 'In Vermont, a 7-member advisory body called the Legislative Apportionment Board drafts and proposes district maps. However, the Vermont General Assembly (state legislature) holds the ultimate authority to enact the final maps as standard legislation, which is subject to the Governor''s signature or veto.', 'https://ballotpedia.org/Redistricting_in_Vermont', 'Ballotpedia - Redistricting in Vermont', '2026-05-17', 'static', 'secondary_source', 'Federal and State candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('01cbec1664772a6a', 'VT', '["federal","state"]', 'redistricting', 'What are the legal criteria for redistricting in Vermont?', '["Standards for drawing Vermont district lines","Vermont gerrymandering rules","Map requirements VT"]', 'Under Vermont statutes, legislative districts must be contiguous, compact, and as nearly equal in population as practicable. The law heavily emphasizes preserving the integrity of political subdivisions, meaning mapping should adhere to county and town boundaries whenever possible.', 'https://sos.vermont.gov/elections/town-clerks/apportionment-board/', 'Vermont Secretary of State - Apportionment Board', '2026-05-17', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('c3bc12010a1ef54c', 'VT', '["state"]', 'redistricting', 'Are the current Vermont state legislative maps operative for the 2026 cycle?', '["Status of Vermont legislative redistricting maps","Are there pending redistricting lawsuits in Vermont?","Vermont 2026 state legislative boundaries"]', 'Yes. The redistricting maps enacted by the Vermont General Assembly in 2022 (following the 2020 census) remain fully operative for the 2026 election cycle without any overriding systemic legal challenges.', 'https://legislature.vermont.gov/', 'Vermont General Assembly', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('ce9be3e91a98ea53', 'VT', '["federal"]', 'redistricting', 'Did Vermont need to redraw its congressional map after the 2020 census?', '["Status of Vermont congressional redistricting","Vermont congressional map 2026","Vermont US House redistricting controversy"]', 'No. Vermont is apportioned only a single, At-Large U.S. House district that covers the entire state. Because it retained only one seat following the 2020 census, congressional redistricting is unnecessary, avoiding any associated mapping controversies.', 'https://sos.vermont.gov/elections/', 'Vermont Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('9580c4673cac8f8b', 'VT', '["state"]', 'recall_rules', 'Does Vermont have a recall mechanism for state officials?', '["Can the Governor of Vermont be recalled?","How to recall a state senator in VT","Statewide recall election rules Vermont"]', 'No. The State of Vermont does not have any constitutional or statutory provision allowing for the recall of state-level elected officials, including the Governor, statewide executives, or members of the General Assembly.', 'https://ballotpedia.org/Laws_governing_recall_in_Vermont', 'Laws governing recall in Vermont', '2026-05-17', 'static', 'secondary_source', 'Statewide and legislative candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('0a22671cba69150e', 'VT', '["county","municipal"]', 'recall_rules', 'What are the rules for local recall in Vermont?', '["Vermont town selectboard recall rules","Signature requirement local recall Vermont","Recalling a mayor in VT"]', 'There is no statewide, general statutory right to recall local officials in Vermont. Recall is only permitted at the municipal level if a specific town or city charter has been explicitly approved by the legislature to include recall provisions.', 'https://ballotpedia.org/Laws_governing_recall_in_Vermont', 'Laws governing recall in Vermont', '2026-05-17', 'static', 'secondary_source', 'Local candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('5d8e613dae5044a5', 'VT', '["state"]', 'ballot_access', 'Does Vermont have a citizen initiative process?', '["How to get an initiative on the VT ballot","Vermont citizen initiative signature requirements","Can citizens propose laws in Vermont?"]', 'No. Vermont is one of the states that does NOT have a statewide citizen initiative process. Citizens cannot draft statutes or constitutional amendments and gather signatures to place them on the ballot. All statewide ballot measures must be referred by the legislature.', 'https://ballotpedia.org/Initiative_and_referendum_in_Vermont', 'Ballotpedia - Initiative and Referendum in Vermont', '2026-05-17', 'static', 'secondary_source', 'Ballot measure committees', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('d327843785eb0425', 'VT', '["state"]', 'ballot_access', 'How does the Vermont legislature refer a constitutional amendment to the voters?', '["Legislative referral process Vermont","Referendum by legislature VT","Can the VT legislature put a constitutional amendment on the ballot?"]', 'Vermont has a highly distinctive, multi-step amendment process. An amendment must first pass the State Senate by a two-thirds (2/3) supermajority, and then the House by a simple majority. In the NEXT biennial legislative session (after an election), it must pass BOTH chambers by a simple majority. Finally, it goes to the voters for ratification.', 'https://ballotpedia.org/Amending_the_Vermont_Constitution', 'Vermont Constitution Chapter II, Section 72', '2026-05-17', 'static', 'statute_citation', 'Legislators and Strategists', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('ff5977a240c8d6da', 'VT', '["state"]', 'ballot_access', 'Does Vermont have a veto referendum process?', '["How to refer a VT bill to the ballot","Vermont citizen referendum rules","Veto referendum signature threshold Vermont state"]', 'No. Vermont does not have a statewide veto referendum process. Citizens cannot gather signatures to suspend and refer an already-passed legislative act to the ballot for a popular vote of approval or rejection.', 'https://ballotpedia.org/Initiative_and_referendum_in_Vermont', 'Ballotpedia - Initiative and Referendum in Vermont', '2026-05-17', 'static', 'secondary_source', 'Ballot measure committees', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('24485cb16da1c8ff', 'VT', '["state"]', 'ballot_access', 'What voter approval threshold is required to pass ballot measures in Vermont?', '["Vermont ballot measure pass threshold","Does a measure need a supermajority in VT?","Majority vote requirements Vermont ballot measures"]', 'In Vermont, a legislatively referred constitutional amendment requires only a simple majority (over 50%) of the total votes cast on that specific measure by voters during a general election to pass.', 'https://sos.vermont.gov/', 'Vermont Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('f0a81c465081c45f', 'VT', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Secretary of State in Vermont?', '["Requirements to run for VT Secretary of State","Who can run for Secretary of State in VT?","Residency rules for Vermont SOS"]', 'Under the Vermont Constitution, the state maintains highly permissive candidate requirements. To run for Secretary of State, an individual simply must be a ''freeman'' (a registered voter) of the state. There are no other enumerated age or specific residency length requirements.', 'https://sos.vermont.gov/elections/election-info-resources/faqs', 'Vermont Secretary of State - Candidate FAQ', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('6d74c94aa5b295d1', 'VT', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for State Treasurer in Vermont?', '["Eligibility for Vermont State Treasurer","Who can run for Treasurer in VT?","Vermont Treasurer residency requirements"]', 'Similar to the Secretary of State, the only constitutional requirement to run for the office of State Treasurer in Vermont is that the candidate must be a ''freeman'' (a registered voter) of the state.', 'https://sos.vermont.gov/elections/election-info-resources/faqs', 'Vermont Secretary of State - Candidate FAQ', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('4346ddd8cbce3cd1', 'VT', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Auditor of Accounts in Vermont?', '["Eligibility for Vermont State Auditor","Who can run for Auditor in VT?","Is a CPA license required for Vermont Auditor?"]', 'The Auditor of Accounts in Vermont is a statewide elected office. The only constitutional requirement to hold this office is that the candidate must be a registered voter of the state. There is no constitutional requirement for the candidate to hold a CPA license or specific financial degree.', 'https://sos.vermont.gov/elections/election-info-resources/faqs', 'Vermont Secretary of State - Candidate FAQ', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('e0acde9a502c6f7b', 'VT', '["municipal"]', 'candidate_eligibility', 'What are the eligibility requirements for a school board candidate in Vermont?', '["Run for school board Vermont requirements","Who can be a school board member in VT?","School board residency rules Vermont"]', 'To run for a local school board in Vermont, candidates must be legally qualified voters and residents of the specific town or school district they seek to represent at the time they are elected.', 'https://sos.vermont.gov/elections/town-clerks/', 'Vermont Secretary of State - Local Offices', '2026-05-17', 'static', 'official_source_direct', 'School board candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('2b74dd95463b6069', 'VT', '["judicial"]', 'candidate_eligibility', 'What are the qualifications for Vermont Supreme Court justices?', '["Vermont Supreme Court Justice eligibility","Years of practice required for VT Supreme Court","Are Vermont judges elected or appointed?"]', 'Vermont Supreme Court justices are appointed, not elected. Candidates must be attorneys licensed to practice in Vermont with at least 10 years of legal experience, including at least five years practicing law in Vermont. They are chosen by the Governor from a Judicial Nominating Board list.', 'https://www.vermontjudiciary.org/about-court/judicial-selection', 'Vermont Judiciary', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('dce7d680d000d8fc', 'VT', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the ballot signature cure process for absentee mail-in ballots in Vermont?', '["How to fix a rejected signature in VT","Vermont ballot cure process deadline","Missing signature on VT mail ballot"]', 'Following the passage of Act 60, Vermont instituted a formal ballot cure process. If a town clerk determines an absentee ballot is defective (e.g., missing signature or unsealed inner envelope), they must notify the voter. The voter is then allowed to cure the defect either in person or by submitting a new ballot before the close of polls on Election Day.', 'https://sos.vermont.gov/elections/voters/early-absentee-voting/', 'Vermont Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('b487184b89fe1336', 'VT', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the deadlines for military and overseas (UOCAVA) voters in Vermont?', '["When are military ballots due in Vermont?","UOCAVA return deadline VT","Overseas voting rules Vermont state"]', 'Under UOCAVA, ballots are transmitted to military and overseas voters at least 45 days before an election. In Vermont, voted ballots (whether returned by mail or submitted electronically) must be received by the town clerk by the close of polls (7:00 p.m.) on Election Day to be counted.', 'https://sos.vermont.gov/elections/voters/military-overseas/', 'Vermont Secretary of State - UOCAVA', '2026-05-17', 'static', 'official_source_direct', 'UOCAVA voters', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('34b2b96e1d268bab', 'VT', '["federal","state","county","municipal"]', 'voter_interaction', 'When are provisional ballots used in Vermont?', '["What is a provisional ballot in VT?","Voting without ID Vermont","When do election workers issue provisional ballots?"]', 'Provisional ballots are extremely rare in Vermont because the state offers unrestricted Same-Day Registration (SDR) everywhere. They are generally only issued if a voter refuses to complete the same-day registration forms, or if a federal or state court orders the polling hours to be extended.', 'https://sos.vermont.gov/elections/voters/voter-faqs/', 'Vermont Secretary of State - Voter FAQs', '2026-05-17', 'static', 'official_source_direct', 'Voters and Poll Watchers', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('65d91e96c005ac32', 'VT', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Vermont have Automatic Voter Registration (AVR) at the DMV?', '["Is registration automatic at the Vermont DMV?","VT motor voter automatic registration","Do I have to register to vote if I get a VT driver''s license?"]', 'Yes. Vermont has utilized Automatic Voter Registration (AVR) since 2017. Any eligible citizen conducting a transaction at the Department of Motor Vehicles is automatically registered to vote or has their address updated, unless they actively decline (opt-out) via the transaction forms.', 'https://sos.vermont.gov/elections/voters/registration/', 'Vermont Secretary of State - Voter Registration', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('d4b8bc902dacc628', 'VT', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Vermont offer Online Voter Registration?', '["Can I register to vote online in VT?","Vermont electronic voter registration","VT MyVoterPage online registration portal"]', 'Yes. Eligible Vermont residents can securely register to vote or update their registration details via the Secretary of State''s online ''My Voter Page'' portal.', 'https://mvp.vermont.gov/', 'Vermont Secretary of State - MyVoterPage', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('5e2d68e30c1ee28b', 'VT', '["federal","state","county","municipal"]', 'voter_interaction', 'How does Vermont maintain its voter registration lists?', '["VT voter list maintenance rules","How are inactive voters handled in Vermont?","Vermont voter roll cleaning process"]', 'Vermont conducts regular list maintenance using the Electronic Registration Information Center (ERIC) and National Change of Address (NCOA) data. Town clerks mail challenge notices to voters whose residency is in question. If they do not respond and fail to vote in two consecutive federal general elections, their names are purged from the checklist.', 'https://sos.vermont.gov/elections/', 'Vermont Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('da802d59af0b6565', 'VT', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the electioneering buffer zone distance in Vermont?', '["How close can I campaign to a polling place in VT?","Vermont electioneering rule inside building","VT buffer zone around voting centers"]', 'Vermont has a relatively localized electioneering rule. Under 17 V.S.A. § 2508, electioneering, campaigning, and displaying political materials are strictly prohibited INSIDE the building containing the polling place. There is no set minimum exterior distance (like 100 feet), but officials must ensure exterior campaigning does not hinder voter access.', 'https://legislature.vermont.gov/statutes/section/17/051/02508', 'Vermont Statutes 17 V.S.A. § 2508', '2026-05-17', 'static', 'statute_citation', 'Campaign workers and Voters', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('e3728829931de443', 'VT', '["state","county","municipal"]', 'runoff_rules', 'Is Ranked Choice Voting (RCV) used in Vermont?', '["Does Vermont use ranked choice voting?","RCV status in Vermont 2026","Instant runoff voting VT Burlington"]', 'Ranked Choice Voting (RCV) is not used for any statewide or federal elections in Vermont. However, it is used locally: the City of Burlington (Vermont''s largest city) utilizes Ranked Choice Voting for its mayoral and city council elections.', 'https://sos.vermont.gov/elections/', 'Vermont Secretary of State', '2026-05-17', 'static', 'secondary_source', 'All candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('aa968952d98f9e07', 'VT', '["federal","state","county"]', 'runoff_rules', 'How are exact ties broken in Vermont elections?', '["How are tied elections decided in Vermont?","Tie-breaker rules Vermont elections","What happens if a race is tied in VT?"]', 'In Vermont, if there is a tie for the top statewide executive offices (Governor, Lt. Governor, Treasurer), the General Assembly decides the winner by a joint ballot. For ties in state legislative or local races, the local court generally orders a special run-off election.', 'https://legislature.vermont.gov/statutes/section/17/051/02602', 'Vermont Statutes 17 V.S.A. § 2602', '2026-05-17', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('1f0d17f6970d617c', 'VT', '["state","county","municipal"]', 'finance_ethics', 'What disclaimer language is required on Vermont campaign materials?', '["Vermont ''Paid for by'' rules","Campaign ad disclaimer requirements VT","Political taglines Vermont SOS"]', 'Under Vermont campaign finance law, all political advertising, mass media, and campaign materials must clearly contain the name and mailing address of the person, candidate, or committee that paid for the communication. (e.g., ''Paid for by [Name], [Address]'').', 'https://outside.vermont.gov/dept/sos/Elections_Division/campaign_finance/campaign_finance_guide.pdf', 'Vermont Secretary of State - Campaign Finance Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates and PACs', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('5e0af85fa16aa246', 'VT', '["state","county","municipal"]', 'finance_ethics', 'When does outside spending become prohibited coordination in Vermont?', '["VT campaign coordination rules","When is a PAC expenditure not independent in Vermont?","Prohibition on candidate-PAC coordination VT"]', 'An ''independent expenditure'' loses its independence and becomes ''coordinated'' if it is made at the request, suggestion, or with the cooperation of a candidate or their committee. Once coordinated, the expenditure is treated legally as an in-kind contribution and strictly applied against the donor''s per-cycle limit.', 'https://outside.vermont.gov/dept/sos/Elections_Division/campaign_finance/campaign_finance_guide.pdf', 'Vermont Secretary of State - Campaign Finance Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates and IECs', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('2d192b87e1adc224', 'VT', '["state","county","municipal"]', 'finance_ethics', 'What are the penalties for late campaign finance filings in Vermont?', '["VT SOS late fee","Penalty for missing a Vermont campaign finance deadline","Secretary of State fine for late filing VT"]', 'The Vermont Secretary of State imposes administrative penalties for late campaign finance reports. Filers who miss a deadline are subject to fines of $10 per day, which accumulate up to a maximum of $1,000 per report.', 'https://outside.vermont.gov/dept/sos/Elections_Division/campaign_finance/campaign_finance_guide.pdf', 'Vermont Secretary of State - Campaign Finance Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('2e17e1d81cf5022a', 'VT', '["state","county","municipal"]', 'finance_ethics', 'When and how must a Vermont campaign committee terminate?', '["Closing a Vermont campaign committee","SOS committee termination requirements","Final campaign finance report Vermont"]', 'A candidate committee may formally terminate by rolling over any surplus funds (to a future campaign or charity), bringing the committee''s account balance to exactly zero, closing the dedicated bank account, and filing a ''Final Report'' through the online campaign finance system.', 'https://outside.vermont.gov/dept/sos/Elections_Division/campaign_finance/campaign_finance_guide.pdf', 'Vermont Secretary of State - Campaign Finance Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('492ab6dfd9c69149', 'VT', '["state","county","municipal"]', 'finance_ethics', 'What are the disclosure rules for independent expenditures in Vermont?', '["VT independent expenditure reporting SOS","Disclosure for VT independent expenditure groups","Reporting thresholds for outside spending Vermont"]', 'Any person, PAC, or entity that makes an independent expenditure (such as mass media activities) advocating for or against a candidate must file an Independent Expenditure Report. If $500 or more is spent within 45 days of the election, the report must be filed within 24 hours.', 'https://sos.vermont.gov/elections/campaign-finance/', 'Vermont Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Independent groups and PACs', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('fd796cc51cda0eb0', 'VT', '["state","county","municipal"]', 'finance_ethics', 'How are in-kind contributions valued and reported in Vermont?', '["Vermont in-kind contribution valuation rules","Reporting non-monetary donations Vermont campaign","Fair market value for in-kind gifts VT"]', 'In-kind contributions (donated goods, services, or equipment not available to the general public) must be reported at their fair market value. Their value is counted directly against the donor''s per-cycle monetary contribution limits.', 'https://outside.vermont.gov/dept/sos/Elections_Division/campaign_finance/campaign_finance_guide.pdf', 'Vermont Secretary of State - Campaign Finance Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('b1e9386c9d139dfb', 'VT', '["state","county","municipal"]', 'finance_ethics', 'Are there limits on a candidate loaning personal funds to their own campaign in Vermont?', '["Vermont candidate personal loan limits","Can I pay myself back for a campaign loan in VT?","Reporting candidate loans in SOS"]', 'No. In Vermont, standard per-cycle contribution limits only apply to external donors. A candidate may loan or contribute an UNLIMITED amount of their own personal funds to their own campaign committee, unless the candidate is participating in the public financing program.', 'https://outside.vermont.gov/dept/sos/Elections_Division/campaign_finance/campaign_finance_guide.pdf', 'Vermont Secretary of State - Campaign Finance Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('33e53bd05795f77e', 'VT', '["state","county","municipal"]', 'finance_ethics', 'What can Vermont candidates do with unexpended campaign funds?', '["What can I do with leftover campaign money in VT?","VT surplus campaign funds rules","Donating remaining campaign funds Vermont"]', 'Surplus campaign funds cannot be converted to personal use. Candidates may carry them forward to a future campaign, return them pro-rata to contributors, or donate them to an IRS-recognized charity or political party. Candidates participating in the public financing program must return all surplus public funds to the state.', 'https://outside.vermont.gov/dept/sos/Elections_Division/campaign_finance/campaign_finance_guide.pdf', 'Vermont Secretary of State - Campaign Finance Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('e9c7990269117e4a', 'VT', '["county","municipal"]', 'election_dates', 'What are the terms and election cycles for local and county offices in Vermont?', '["When are county sheriffs elected in VT?","Vermont local official term lengths","Town Meeting Day elections Vermont"]', 'Vermont''s county-level officials (like Sheriffs, State''s Attorneys, and Probate Judges) are elected during the November general election in even-numbered years for four-year terms. However, most local town officials (like selectboard members) are traditionally elected on Town Meeting Day, which is held annually on the first Tuesday in March.', 'https://sos.vermont.gov/elections/town-clerks/', 'Vermont Secretary of State', '2026-05-17', 'per_cycle', 'official_source_direct', 'County and Local candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('f9dc81dc55c9c12b', 'VT', '["state","county","municipal"]', 'election_dates', 'What is the canvassing and certification timeline for Vermont elections?', '["When are Vermont election results official?","VT certification deadline","State Canvassing Committee meeting Vermont"]', 'Local town clerks report results within 48 hours of the election. The state canvassing committee then officially convenes at the Secretary of State''s office on the third Tuesday in August for primary elections, and the third Tuesday in November for general elections, to certify the final returns.', 'https://legislature.vermont.gov/statutes/section/17/051/02592', 'Vermont Statutes 17 V.S.A. § 2592', '2026-05-17', 'static', 'statute_citation', 'All candidates and campaigns', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('acd058cb8b733a27', 'VT', '["federal","state"]', 'election_dates', 'When and how are special elections called in Vermont?', '["Vermont special election timeline","Who calls a special election to fill a US House vacancy in VT?","Filling a midterm vacancy Vermont"]', 'Special elections to fill a vacancy in a federal or state legislative office are called by a writ of election issued by the Governor. State legislative vacancies are often filled by a gubernatorial appointment (from the vacating member''s party) if sufficient time does not remain to hold an election.', 'https://sos.vermont.gov/elections/', 'Vermont Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1'),
  ('e852c4ee8226c307', 'VT', '["state"]', 'election_dates', 'What is the role of the State Ethics Commission in Vermont elections?', '["Who handles ethics disclosures in VT?","Vermont State Ethics Commission structure","Candidate financial disclosure Vermont"]', 'Created relatively recently, the Vermont State Ethics Commission provides guidance and enforces compliance for state officials. Crucially for candidates, the Commission receives and reviews the mandatory Financial Disclosure forms and IRS Form 1040 submissions required of state-level candidates when they file for office.', 'https://ethicscommission.vermont.gov/', 'Vermont State Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T23-15-46_vermont_full_v1')
